import requests

def test_hr_admin_update_leave_request_missing_mandatory_field(
    auth_token, base_url, audit_client
):
    headers = {"Authorization": f"Bearer {auth_token}"}
    payload = {"reason": "approval"}
    resp = requests.post(
        f"{base_url}/leave-requests/lr-002",
        json=payload,
        headers=headers
    )
    assert resp.status_code == 400
    error = resp.json()
    assert "status" in error["message"].lower()

    audit_logs = audit_client.query(
        event_type="leave_request_update",
        entity_id="lr-002"
    )
    assert len(audit_logs) == 0

import requests

def test_hr_admin_update_leave_request_insufficient_role(
    employee_token, base_url
):
    headers = {"Authorization": f"Bearer {employee_token}"}
    payload = {
        "status": "approved",
        "reason": "test"
    }
    resp = requests.post(
        f"{base_url}/leave-requests/lr-003",
        json=payload,
        headers=headers
    )
    assert resp.status_code == 403
    error = resp.json()
    assert "forbidden" in error["message"].lower() or \
           "not authorized" in error["message"].lower()

import requests

def test_hr_admin_update_leave_request_max_length_reason_field(
    auth_token, base_url
):
    headers = {"Authorization": f"Bearer {auth_token}"}
    max_reason = "x" * 500
    payload = {
        "status": "approved",
        "reason": max_reason
    }
    resp = requests.post(
        f"{base_url}/leave-requests/lr-005",
        json=payload,
        headers=headers
    )
    assert resp.status_code == 200
    data = resp.json()
    assert data["reason"] == max_reason
    assert len(data["reason"]) == 500

