def test_hr_admin_update_leave_request_exceeds_max_length_reason(
    auth_token, base_url
):
    headers = {"Authorization": f"Bearer {auth_token}"}
    oversized_reason = "x" * 501
    payload = {
        "status": "approved",
        "reason": oversized_reason
    }
    resp = requests.post(
        f"{base_url}/leave-requests/lr-006",
        json=payload,
        headers=headers
    )
    assert resp.status_code == 400
    error = resp.json()
    assert "reason" in error["message"].lower() and \
           "length" in error["message"].lower()
